{"file_path":"/project/MultiLineIfElseElseIfBlockTest.kt","content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class MultiLineIfElseElseIfBlockTest {
    private val multiLineIfElseRuleAssertThat = assertThatRule { MultiLineIfElseRule() }

    @Test
    fun `Issue - Given multiline else if statement with blocks should not be reformatted`() {
        val code =
            """
            val x = if (showFilter) {
                1
            } else if (activeTabIndex.value == 0) {
                2
            } else {
                null
            } ?: 0
            """.trimIndent()
        multiLineIfElseRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Issue - Given multiline else if statement with blocks and trailing call should not be reformatted`() {
        val code =
            """
            val foo = if (bar1) {
                "bar1"
            } else if (bar2) {
                "bar2"
            } else {
                "bar3"
            }.plus("foo")
            """.trimIndent()
